{
  "exercises": [
    {
      "sentence": "Je ___ un sac pour voyager.",
      "wordBank": ["ai", "aime", "suis", "vais"],
      "correctAnswer": "ai",
      "explanation": "Bei A1-Niveau verwendet man 'avoir' (haben) mit 'je'. 'J'ai' ist die richtige Form für 'ich habe'. Die anderen Wörter passen grammatisch nicht."
    },
    {
      "sentence": "Elle ___ le train pour Paris.",
      "wordBank": ["aime", "va", "voit", "a"],
      "correctAnswer": "va",
      "explanation": "'aller' (gehen) im Präsens: 'elle va' bedeutet 'sie geht'. Bei A1 ist dies eine einfache Verwendung des Verbs 'aller'."
    },
    {
      "sentence": "Nous ___ un hôtel à Lyon.",
      "wordBank": ["aimons", "avons", "voyageons", "sommes"],
      "correctAnswer": "avons",
      "explanation": "'avoir' im Präsens: 'nous avons' = wir haben. Dies ist eine einfache Verwendung des grundlegenden Verbs 'avoir'."
    },
    {
      "sentence": "Tu ___ les pays étrangers.",
      "wordBank": ["aimes", "es", "as", "va"],
      "correctAnswer": "aimes",
      "explanation": "'aimer' (mögen) im Präsens: 'tu aimes' = du magst. Dies ist eine häufige A1-Verwendung mit dem Verb 'aimer'."
    },
    {
      "sentence": "Il ___ un passeport.",
      "wordBank": ["a", "est", "voit", "aime"],
      "correctAnswer": "a",
      "explanation": "'avoir' im Präsens: 'il a' = er hat. Das ist eine der einfachsten Verbindungen für A1-Lernende."
    }
  ]
}
